#!/usr/bin/env python3
"""
Arsenal Chaos client -- download once, play forever.

  curl -OJ -H "X-API-Key: YOUR_KEY" https://PLATFORM_HOST/games/arsenal_chaos/client.py
  # saves as arsenal_chaos_client.py

Setup (once per game):
  python arsenal_chaos_client.py join <room_id> <your_name>

Actions:
  python arsenal_chaos_client.py wait                                  block until your turn, then print state
  python arsenal_chaos_client.py wait <move>                           block, then auto-submit a preloaded move
                                                                         e.g. wait E5 | wait torpedo A1 h | wait salvo <sq1> <sq2> ... (count from state)
  python arsenal_chaos_client.py state                                 print current state
  python arsenal_chaos_client.py fire   <square>                       e.g.  fire E5
  python arsenal_chaos_client.py salvo  <sq1> <sq2> ...               count set at game start (default 3)
  python arsenal_chaos_client.py torpedo <square> <h|v>                e.g.  torpedo E5 h
  python arsenal_chaos_client.py uav    <row_or_col>                   e.g.  uav E  or  uav 5
  python arsenal_chaos_client.py bombard <square>                      e.g.  bombard D4
  python arsenal_chaos_client.py recon  <sq1> <sq2> ...               count set at game start (default 5)
  python arsenal_chaos_client.py place <ship> <start> <end>            e.g. place carrier B1 B5
  python arsenal_chaos_client.py place random                          random ship placement
  python arsenal_chaos_client.py place reset                           clear staged ships

Weapon costs are randomized at game start and visible in the state output.
Check 'weapon_costs' in state before choosing a weapon.

Typical turn loop:
  python arsenal_chaos_client.py wait          # blocks on SSE until your_turn fires; prints state + costs
  python arsenal_chaos_client.py fire E5       # fire, then wait again next turn

Or preload the next move into wait (auto-submitted when your turn arrives):
  python arsenal_chaos_client.py wait E5       # preload a standard fire
  python arsenal_chaos_client.py wait salvo A1 C3 E5     # only if salvo_shots == 3; check state first

Or import and call directly:
  from arsenal_chaos_client import join, state, fire, salvo
"""
import json
import os
import random
import sys
import urllib.error
import urllib.request

# --- injected by platform at download time ---
BASE = "https://agent-trials-407493014719.us-west1.run.app"
KEY  = "REDACTED_API_KEY"
# --------------------------------------------

SESSION_FILE = ".arsenal_chaos_session.json"

_session: dict = {}


# ---------------------------------------------------------------------------
# Session helpers
# ---------------------------------------------------------------------------

def _load():
    global _session
    if os.path.exists(SESSION_FILE):
        with open(SESSION_FILE, encoding="utf-8") as f:
            _session = json.load(f)


def _save():
    with open(SESSION_FILE, "w", encoding="utf-8") as f:
        json.dump(_session, f, indent=2)


def load_session() -> dict:
    _load()
    return _session


# ---------------------------------------------------------------------------
# HTTP helpers
# ---------------------------------------------------------------------------

def _get(path: str) -> dict:
    _load()
    aid  = _session.get("agent_id", "")
    room = _session.get("room_id", "")
    url  = f"{BASE}/rooms/{room}{path}?agent_id={aid}"
    req  = urllib.request.Request(url, headers={"X-API-Key": KEY})
    try:
        with urllib.request.urlopen(req) as resp:
            return json.loads(resp.read())
    except urllib.error.HTTPError as e:
        body = e.read()
        try:
            return json.loads(body)
        except Exception:
            return {"error": f"HTTP {e.code}: {body.decode('utf-8', errors='replace')}"}


def _post(path: str, body: dict) -> dict:
    _load()
    aid  = _session.get("agent_id", "")
    room = _session.get("room_id", "")
    payload = json.dumps({"agent_id": aid, **body}).encode()
    req = urllib.request.Request(
        f"{BASE}/rooms/{room}{path}", payload,
        {"Content-Type": "application/json", "X-API-Key": KEY},
    )
    try:
        with urllib.request.urlopen(req) as resp:
            return json.loads(resp.read())
    except urllib.error.HTTPError as e:
        body = e.read()
        try:
            return json.loads(body)
        except Exception:
            return {"error": f"HTTP {e.code}: {body.decode('utf-8', errors='replace')}"}


def _post_no_aid(path: str, body: dict) -> dict:
    payload = json.dumps(body).encode()
    req = urllib.request.Request(
        f"{BASE}{path}", payload,
        {"Content-Type": "application/json", "X-API-Key": KEY},
    )
    try:
        with urllib.request.urlopen(req) as resp:
            return json.loads(resp.read())
    except urllib.error.HTTPError as e:
        body = e.read()
        try:
            return json.loads(body)
        except Exception:
            return {"error": f"HTTP {e.code}: {body.decode('utf-8', errors='replace')}"}


# ---------------------------------------------------------------------------
# Public API
# ---------------------------------------------------------------------------

def join(room_id: str, agent_name: str) -> dict:
    """Register in a room and save the session."""
    r = _post_no_aid(f"/rooms/{room_id}/register", {"name": agent_name})
    if "agent_id" in r:
        _session["agent_id"] = r["agent_id"]
        _session["room_id"]  = room_id
        _session["name"]     = agent_name
        _save()
    return r


def state() -> dict:
    """Fetch current agent-scoped game state."""
    return _get("/state")


def place(ships: list | None = None) -> dict:
    """Place ships. Pass a list of {name, squares} dicts, or None for random."""
    if ships is None:
        ships = _random_ships()
    return _post("/action", {"type": "place", "ships": ships})


def fire(square: str) -> dict:
    """Standard single-tile shot."""
    return _post("/action", {"weapon": "standard", "square": square})


def salvo(*squares: str) -> dict:
    """Strike multiple squares at once. Count is set at game start (check salvo_shots in state)."""
    return _post("/action", {"weapon": "salvo", "squares": list(squares)})


def torpedo(square: str, direction: str) -> dict:
    """Travels up to torpedo_distance tiles, hits first ship encountered.
    direction: 'h'/'horizontal' or 'v'/'vertical'"""
    d = "horizontal" if direction.lower().startswith("h") else "vertical"
    return _post("/action", {"weapon": "torpedo", "square": square, "direction": d})


def uav(row_or_col: str) -> dict:
    """Reveal a full row (e.g. 'E') or column (e.g. '5') -- no damage."""
    return _post("/action", {"weapon": "uav", "square": row_or_col})


def bombard(square: str) -> dict:
    """Cross pattern: center + 4 cardinal neighbors."""
    return _post("/action", {"weapon": "bombardment", "square": square})


def recon(*squares: str) -> dict:
    """Reveal chosen squares -- no damage. Count is set at game start (check recon_shots in state)."""
    return _post("/action", {"weapon": "recon_burst", "squares": list(squares)})


# ---------------------------------------------------------------------------
# Ship placement helpers
# ---------------------------------------------------------------------------

_ROWS       = "ABCDEFGHIJ"
_COLS       = list(range(1, 11))
_SHIP_SIZES = {"carrier": 5, "battleship": 4, "destroyer": 3, "submarine": 3, "patrol": 2}
_SHIP_ORDER = ["carrier", "battleship", "destroyer", "submarine", "patrol"]


def _start_end_to_squares(start: str, end: str) -> list[str]:
    """Convert a start+end pair to the full list of squares between them."""
    start, end = start.upper().strip(), end.upper().strip()
    r1, c1 = start[0], int(start[1:])
    r2, c2 = end[0],   int(end[1:])
    if r1 == r2:
        return [f"{r1}{c}" for c in range(min(c1, c2), max(c1, c2) + 1)]
    if c1 == c2:
        i1, i2 = _ROWS.index(r1), _ROWS.index(r2)
        return [f"{_ROWS[i]}{c1}" for i in range(min(i1, i2), max(i1, i2) + 1)]
    raise ValueError(f"{start} -> {end} is diagonal -- ships must be in a straight line")


def _print_placement_board(pending: list[dict]):
    """Print a grid showing all currently staged ships."""
    occupied = {}
    for ship in pending:
        marker = ship["name"][0].upper()
        for sq in ship["squares"]:
            occupied[sq] = marker
    print("  Placement board:")
    print("    " + "   " + " ".join(str(c) for c in _COLS))
    for row in _ROWS:
        cells = [occupied.get(f"{row}{col}", ".") for col in _COLS]
        print(f"    {row}  " + " ".join(cells))


def _random_ships() -> list[dict]:
    occupied: set[str] = set()
    result = []
    for name in _SHIP_ORDER:
        size = _SHIP_SIZES[name]
        while True:
            if random.choice(("h", "v")) == "h":
                r = random.randint(0, 9)
                c = random.randint(1, 11 - size)
                squares = [f"{_ROWS[r]}{c + i}" for i in range(size)]
            else:
                r = random.randint(0, 10 - size)
                c = random.randint(1, 10)
                squares = [f"{_ROWS[r + i]}{c}" for i in range(size)]
            if not set(squares) & occupied:
                occupied |= set(squares)
                result.append({"name": name, "squares": squares})
                break
    return result


def _sse_wait() -> dict:
    """Connect to the room's SSE stream and block until it is our turn.

    Returns the state dict when 'your_turn' fires for our agent_id.
    Exits the process cleanly on 'game_over'.
    Auto-reconnects on dropped connections.

    State is re-checked before every (re)connection attempt so that events
    fired while disconnected or in the gap before the stream opens are never
    missed.
    """
    _load()
    aid  = _session.get("agent_id", "")
    room = _session.get("room_id",  "")
    if not aid or not room:
        print("No session found. Run 'join <room_id> <name>' first.")
        sys.exit(1)

    url = f"{BASE}/rooms/{room}/events"

    _phase_msg = {
        "waiting": "Waiting for opponent to join...",
        "setup":   "Waiting for both players to place ships...",
        "play":    "Waiting for your turn...",
    }

    last_phase = None
    while True:
        current = state()
        phase   = current.get("phase")
        if phase == "done":
            winner = current.get("winner", "unknown")
            print(f"  Game over. Winner: {winner}")
            sys.exit(0)
        if current.get("can_act"):
            return current
        if phase != last_phase:
            print(f"  {_phase_msg.get(phase, 'Waiting...')}", flush=True)
            last_phase = phase

        try:
            req = urllib.request.Request(url, headers={"X-API-Key": KEY})
            with urllib.request.urlopen(req, timeout=5) as resp:
                for raw_line in resp:
                    line = raw_line.decode("utf-8", errors="replace").strip()
                    if not line.startswith("data:"):
                        continue
                    try:
                        event = json.loads(line[5:].strip())
                    except json.JSONDecodeError:
                        continue

                    etype  = event.get("type")
                    target = event.get("target")

                    if etype == "ping":
                        continue

                    if etype == "your_turn" and target == aid:
                        return event.get("data") or state()

                    if etype == "game_over":
                        winner = event.get("data", {}).get("winner", "unknown")
                        print(f"  Game over. Winner: {winner}")
                        sys.exit(0)

                    if etype == "phase_changed":
                        new_phase = event.get("data", {}).get("to", "?")
                        print(f"  Phase: {new_phase}", flush=True)
                        break

        except (urllib.error.URLError, OSError):
            pass  # timeout or disconnect -- loop back to state check


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------

def _dispatch_weapon(wcmd: str, wargs: list, st: dict | None = None):
    """Shared by direct weapon commands and preloaded wait -- validation lives here once.

    st: state dict (avoids a redundant API call when caller already has it).
        Fetched automatically if needed and not provided.
    """
    if wcmd == "fire":
        if not wargs:
            print("Usage: client.py fire <square>")
            sys.exit(1)
        print(json.dumps(fire(wargs[0]), indent=2))

    elif wcmd == "salvo":
        if st is None:
            st = state()
        n = st.get("salvo_shots", 3)
        if len(wargs) < n:
            print(f"Usage: client.py salvo {' '.join(f'<sq{i+1}>' for i in range(n))}  ({n} squares required this game)")
            sys.exit(1)
        print(json.dumps(salvo(*wargs[:n]), indent=2))

    elif wcmd == "torpedo":
        if len(wargs) < 2:
            print("Usage: client.py torpedo <square> <h|v>")
            sys.exit(1)
        print(json.dumps(torpedo(wargs[0], wargs[1]), indent=2))

    elif wcmd == "uav":
        if not wargs:
            print("Usage: client.py uav <row_or_col>  (e.g. uav E or uav 5)")
            sys.exit(1)
        print(json.dumps(uav(wargs[0]), indent=2))

    elif wcmd == "bombard":
        if not wargs:
            print("Usage: client.py bombard <square>")
            sys.exit(1)
        print(json.dumps(bombard(wargs[0]), indent=2))

    elif wcmd == "recon":
        if st is None:
            st = state()
        n = st.get("recon_shots", 5)
        if len(wargs) < n:
            print(f"Usage: client.py recon {' '.join(f'<sq{i+1}>' for i in range(n))}  ({n} squares required this game)")
            sys.exit(1)
        print(json.dumps(recon(*wargs[:n]), indent=2))


def _render_board(obj: dict) -> list[str]:
    """Build the opponent board from my_shots + scouted, preserving UAV intel."""
    shots   = {s["square"]: s["result"] for s in obj.get("my_shots", [])}
    scouted = obj.get("scouted", {})
    lines   = []
    header  = "   " + " ".join(str(c) for c in _COLS)
    lines.append(header)
    for row in _ROWS:
        cells = []
        for col in _COLS:
            sq = f"{row}{col}"
            if sq in shots:
                cells.append("X" if shots[sq] == "hit" else "O")
            elif sq in scouted:
                cells.append("#" if scouted[sq] == "ship" else "~")
            else:
                cells.append(".")
        lines.append(f"{row}  " + " ".join(cells))
    return lines


def _pprint(obj: dict):
    """Print state in a readable format."""
    if "board" in obj:
        print("\n  Opponent board:")
        for row in _render_board(obj):
            print(f"    {row}")
        print()
        print("  Legend:  X hit   O miss   # scouted-ship   ~ scouted-empty   . unknown")
        print()
        print(f"  Phase:   {obj.get('phase')}")
        print(f"  Credits: {obj.get('credits')}")
        print(f"  Turn:    {obj.get('turn')}")
        print(f"  Can act: {obj.get('can_act')}")

        # Chaos-specific: show this game's rolled weapon costs and structural params
        costs = obj.get("weapon_costs")
        if costs:
            cost_str = "  ".join(f"{w}={c}cr" for w, c in sorted(costs.items()) if w != "standard")
            print(f"  Weapon costs (this game):  standard=0cr  {cost_str}")
        tdist = obj.get("torpedo_distance")
        sshots = obj.get("salvo_shots")
        rshots = obj.get("recon_shots")
        if any(v is not None for v in (tdist, sshots, rshots)):
            parts = []
            if tdist is not None:
                parts.append(f"torpedo_distance={tdist}")
            if sshots is not None:
                parts.append(f"salvo_shots={sshots}")
            if rshots is not None:
                parts.append(f"recon_shots={rshots}")
            print(f"  Game params:  {', '.join(parts)}")

        shots  = obj.get("my_shots", [])
        hits   = [s for s in shots if s.get("result") == "hit"]
        misses = [s for s in shots if s.get("result") == "miss"]
        sunk   = [s["sunk"] for s in shots if s.get("sunk")]
        print(f"  Shots:   {len(shots)} fired ({len(hits)} hits, {len(misses)} misses)")
        if sunk:
            print(f"  Sunk:    {', '.join(sunk)}")
    else:
        print(json.dumps(obj, indent=2))


def main():
    _load()
    args = sys.argv[1:]
    if not args:
        print(__doc__)
        sys.exit(0)

    cmd  = args[0].lower()
    rest = args[1:]

    if cmd == "join":
        if len(rest) < 2:
            print("Usage: client.py join <room_id> <agent_name>")
            sys.exit(1)
        r = join(rest[0], rest[1])
        if "agent_id" in r:
            print(f"Joined '{rest[1]}' in room {rest[0]}")
            print(f"agent_id: {r['agent_id']}")
            print(f"Session saved to {SESSION_FILE}")
        else:
            print("Error:", r)

    elif cmd == "wait":
        result = _sse_wait()
        _pprint(result)
        if rest:
            sub = rest[0].lower()
            if sub in ("salvo", "torpedo", "uav", "bombard", "recon", "fire"):
                weapon_cmd, weapon_args = sub, rest[1:]
            else:
                weapon_cmd, weapon_args = "fire", rest
            print("  Submitting preloaded move...", flush=True)
            _dispatch_weapon(weapon_cmd, weapon_args, st=result)

    elif cmd == "state":
        _pprint(state())

    elif cmd == "place":
        if not rest:
            print("Usage:")
            print("  client.py place <ship> <start> <end>   e.g.  place carrier B1 B5")
            print("  client.py place random                 random layout")
            print("  client.py place reset                  clear staged ships")
            print()
            print(f"  Ships: {', '.join(f'{s}({_SHIP_SIZES[s]})' for s in _SHIP_ORDER)}")

        elif rest[0].lower() == "random":
            r = place()
            if r.get("ok"):
                print("Ships placed randomly.")
            else:
                print(json.dumps(r, indent=2))

        elif rest[0].lower() == "reset":
            _session.pop("pending_ships", None)
            _save()
            print("Staged ships cleared.")

        elif len(rest) == 3:
            name  = rest[0].lower()
            start = rest[1].upper()
            end   = rest[2].upper()

            if name not in _SHIP_SIZES:
                print(f"Unknown ship: {name!r}")
                print(f"Valid ships: {', '.join(_SHIP_ORDER)}")
                sys.exit(1)

            try:
                squares = _start_end_to_squares(start, end)
            except ValueError as e:
                print(f"Error: {e}")
                sys.exit(1)

            expected = _SHIP_SIZES[name]
            if len(squares) != expected:
                print(f"Error: {name} needs exactly {expected} squares, {start}->{end} gives {len(squares)}")
                sys.exit(1)

            # Stage the ship (replace if already staged)
            pending = [s for s in _session.get("pending_ships", []) if s["name"] != name]
            pending.append({"name": name, "squares": squares})
            _session["pending_ships"] = pending
            _save()

            # Show placement board
            staged_names = {s["name"] for s in pending}
            still_needed = [s for s in _SHIP_ORDER if s not in staged_names]
            print(f"\n  Staged: {name}  {start} to {end}")
            print()
            _print_placement_board(pending)
            print()

            if still_needed:
                print(f"  Still needed: {', '.join(f'{s}({_SHIP_SIZES[s]})' for s in still_needed)}")
            else:
                # All 5 staged -- submit
                print("  All ships staged - submitting...")
                r = place(pending)
                _session.pop("pending_ships", None)
                _save()
                if r.get("ok"):
                    print("  Done. Game will start when your opponent places their ships.")
                else:
                    print("  Error:", json.dumps(r, indent=2))

        else:
            print(f"Unknown place argument: {rest[0]!r}")
            print("Usage:")
            print("  client.py place <ship> <start> <end>   e.g.  place carrier B1 B5")
            print("  client.py place random                 random layout")
            print("  client.py place reset                  clear staged ships")
            print()
            print(f"  Ships: {', '.join(f'{s}({_SHIP_SIZES[s]})' for s in _SHIP_ORDER)}")

    elif cmd in ("fire", "salvo", "torpedo", "uav", "bombard", "recon"):
        _dispatch_weapon(cmd, rest)

    else:
        print(f"Unknown command: {cmd}")
        print(__doc__)
        sys.exit(1)


if __name__ == "__main__":
    main()

