#!/usr/bin/env python3
"""Battleship Probability Calculator - Track likely ship locations"""

import json
from collections import defaultdict

# Ship sizes
SHIPS = {'carrier': 5, 'battleship': 4, 'destroyer': 3, 'submarine': 3, 'patrol': 2}

def generate_all_positions():
    """Generate all valid ship positions (square, horizontal/vertical)"""
    positions = defaultdict(list)
    for row in 'ABCDEFGHIJ':
        for col in range(1, 11):
            # Horizontal positions
            for ship_name, size in SHIPS.items():
                squares = []
                valid = True
                for i in range(size):
                    c = col + i
                    if c > 10:
                        valid = False
                        break
                    squares.append(f"{row}{c}")
                if valid:
                    positions[ship_name].append(('h', squares))

            # Vertical positions
            for ship_name, size in SHIPS.items():
                squares = []
                valid = True
                for i in range(size):
                    r = chr(ord(row) + i)
                    if r > 'J':
                        valid = False
                        break
                    squares.append(f"{r}{col}")
                if valid:
                    positions[ship_name].append(('v', squares))
    return positions

def calculate_probabilities(hits, misses, sunk_ships):
    """Calculate probability for each square based on current state"""
    all_positions = generate_all_positions()
    probabilities = defaultdict(float)

    # Remove positions that conflict with known info
    for ship_name, positions in all_positions.items():
        if ship_name in sunk_ships:
            continue

        for orientation, squares in positions:
            # Check if position conflicts with misses
            if any(s in misses for s in squares):
                continue
            # Check if position explains all hits
            if not any(s in hits for s in squares):
                continue

            # Add probability weight
            weight = 1.0 / len(positions)  # Uniform for now
            for s in squares:
                probabilities[s] += weight

    return probabilities

def get_best_targets(hits, misses, sunk_ships, count=5):
    """Get top target squares based on probability"""
    probs = calculate_probabilities(hits, misses, sunk_ships)

    # Filter out already-hit squares
    candidates = {k: v for k, v in probs.items() if k not in hits and k not in misses}

    # Sort by probability
    sorted_targets = sorted(candidates.items(), key=lambda x: x[1], reverse=True)

    return sorted_targets[:count]

if __name__ == "__main__":
    # Test
    hits = ['C3', 'C4']
    misses = ['A1', 'B2', 'C5']
    sunk_ships = ['battleship']

    targets = get_best_targets(hits, misses, sunk_ships)
    print("Best targets:", targets)
