            print()
            print(f"  Ships: {', '.join(f'{s}({_SHIP_SIZES[s]})' for s in _SHIP_ORDER)}")

        elif rest[0].lower() == "random":
            r = place()
            if r.get("ok"):
                print("Ships placed randomly.")
            else:
                print(json.dumps(r, indent=2))

        elif rest[0].lower() == "reset":
            _session.pop("pending_ships", None)
            _save()
            print("Staged ships cleared.")

        elif len(rest) == 3:
            name  = rest[0].lower()
            start = rest[1].upper()
            end   = rest[2].upper()

            if name not in _SHIP_SIZES:
                print(f"Unknown ship: {name!r}")
                print(f"Valid ships: {', '.join(_SHIP_ORDER)}")
                sys.exit(1)

            try:
                squares = _start_end_to_squares(start, end)
            except ValueError as e:
                print(f"Error: {e}")
                sys.exit(1)

            expected = _SHIP_SIZES[name]
            if len(squares) != expected:
                print(f"Error: {name} needs exactly {expected} squares, {start}->{end} gives {len(squares)}")
                sys.exit(1)

            # Stage the ship (replace if already staged)
            pending = [s for s in _session.get("pending_ships", []) if s["name"] != name]
            pending.append({"name": name, "squares": squares})
            _session["pending_ships"] = pending
            _save()

            # Show placement board
            staged_names = {s["name"] for s in pending}
            still_needed = [s for s in _SHIP_ORDER if s not in staged_names]
            print(f"\n  Staged: {name}  {start} to {end}")
            print()
            _print_placement_board(pending)
            print()

            if still_needed:
                print(f"  Still needed: {', '.join(f'{s}({_SHIP_SIZES[s]})' for s in still_needed)}")
            else:
                # All 5 staged -- submit
                print("  All ships staged - submitting...")
                r = place(pending)
                _session.pop("pending_ships", None)
                _save()
                if r.get("ok"):
                    print("  Done. Game will start when your opponent places their ships.")
                else:
                    print("  Error:", json.dumps(r, indent=2))

        else:
            print(f"Unknown place argument: {rest[0]!r}")
            print("Usage:")
            print("  client.py place <ship> <start> <end>   e.g.  place carrier B1 B5")
            print("  client.py place random                 random layout")
            print("  client.py place reset                  clear staged ships")
            print()
            print(f"  Ships: {', '.join(f'{s}({_SHIP_SIZES[s]})' for s in _SHIP_ORDER)}")

    elif cmd in ("fire", "salvo", "torpedo", "uav", "bombard", "recon"):
        _dispatch_weapon(cmd, rest)

    else:
        print(f"Unknown command: {cmd}")
        print(__doc__)
        sys.exit(1)


if __name__ == "__main__":
    main()

