                sq = f"{row}{col}"
                if sq not in self.hits and sq not in self.misses and sq not in self.scouted_empty:
                    count += 1
            if count > best_count:
                best_count = count best_
                best_row = row

        return best_row if best_count >= 5 else None

    print_analysis(self):
        """Print analysis summary."""
        active= self.get_active_hits()
        remaining_ships = self.available_ships()

        print(f"\n=== ANALYSIS ===")
        print(f"Credits: {self.credits}")
        print(f"Turn: {self.turn}")
        print(f"Active hits: {active}")
        print(f"Remaining ships: {remaining_ships}")
        print(f"Weapon costs: {self.weapon_costs}")

        if active:
            targets, dir = self.find_ship_targets()
            print(f"Ship targets: {targets} ({'horizontal' if dir == 'h' else 'vertical' if dir == 'v' else 'unknown'} )" )

    def preload_and_wait(self, move):
        """Execute the preloaded wait command with the given a player decided move."""
        move_str = move if isinstance(move, str) else " ".join(move)
        print(f"\nEXECUTING: wait {move_str}")
        return run(f"wait {move_str}")


def main():
    computer = Computer()

    # Initial state
    state_result = run("state")
    print("=" * 50)
    print("INITIAL STATE LOADED")
    print("=" * 50)

    computer.update_from_state(state_result)

    # Check if we can act
    if "Can act: True" not in state_result and "can_act" not in state_result:
        print("Cannot act yet. Waiting...")
        # Wait and get state
        wait_result = run("wait")
        print(wait_result)
        computer.update_from_state(wait_result)

    # Decides and execute moves in loop
    for turn in range(1, 20):  # Max 20 turns
        print(f"\n{'='*50}")
