#!/usr/bin/env python3
"""Probability calculator for Arsenal Chaos - run during game."""
import re, sys, os

SHIPS = [("carrier",5), ("battleship",4), ("destroyer",3), ("submarine",3), ("patrol",2)]
ROWS = "ABCDEFGHIJ"

def parse_state(filepath=".arsenal_chaos_session.json"):
    """Read state via the client."""
    import subprocess
    r = subprocess.run("python.exe arsenal_chaos_client.py state", shell=True,
                       capture_output=True, text=True, cwd=os.path.dirname(filepath) or ".")
    return r.stdout

def extract_data(text):
    hits, misses, scouted_ships, scouted_empty, sunk, credits, turn, costs = set(), set(), set(), set(), [], 5, 0, {}
    in_board = False
    for line in text.split("\n"):
        if "Opponent board:" in line:
            in_board = True; continue
        if not in_board: continue
        row_match = re.match(r"^([A-J])\s+(.*)", line)
        if row_match:
            row, cells = row_match.group(1), row_match.group(2).split()
            for i, c in enumerate(cells):
                sq = row + str(i+1)
                if c == "X": hits.add(sq)
                elif c == "O": misses.add(sq)
                elif c == "#": scouted_ships.add(sq)
                elif c == "~": scouted_empty.add(sq)
        elif "Credits:" in line:
            m = re.search(r"Credits:\s*(\d+)", line)
            if m: credits = int(m.group(1))
        elif "Turn:" in line:
            m = re.search(r"Turn:\s*(\d+)", line)
            if m: turn = int(m.group(1))
        elif "Sunk:" in line:
            rest = line.split("Sunk:")[1].strip()
            for s in [x[0] for x in SHIPS]:
                if s in rest.lower(): sunk.append(s)
        elif "Weapon costs" in line:
            for part in line.split():
                if "=" in part and "cr" in part:
                    name, val = part.split("=")
                    costs[name] = int(val.replace("cr", ""))
        elif "standard=" in line:
            for part in line.split():
                if "=" in part:
                    parts = part.split("=")
                    if len(parts) == 2:
                        costs[parts[0]] = int(parts[1].replace("cr",""))
    return hits, misses, scouted_ships, scouted_empty, sunk, credits, turn, costs

def compute_probabilities(hits, misses, scouted_ships, scouted_empty, sunk):
    """Compute probability for each square based on remaining ships."""
    active = [s for s in SHIPS if s[0] not in sunk]
    probs = {}
    all_squares = [f"{r}{c}" for r in ROWS for c in range(1, 11)]
    for sq in all_squares:
        probs[sq] = 0.0

    if not active:
        return probs

    total_positions = 0
    for name, size in active:
        # Horizontal positions
        for r in ROWS:
            for c in range(1, 11 - size + 1):
                sqs = [f"{r}{c+i}" for i in range(size)]
                # Check validity
                valid = True
                for s in sqs:
                    if s in misses and s not in hits:
                        valid = False; break
                    if s in scouted_empty and s not in scouted_ships and s not in hits:
                        valid = False; break
                if not valid: continue
                # Must overlap hits if we have hits
                if hits and not any(s in hits for s in sqs):
                    continue
                total_positions += 1
                for s in sqs:
                    probs[s] = probs.get(s, 0) + 1

        # Vertical positions
        for ri in range(10 - size + 1):
            for c in range(1, 11):
                sqs = [f"{ROWS[ri+i]}{c}" for i in range(size)]
                valid = True
                for s in sqs:
                    if s in misses and s not in hits:
                        valid = False; break
                    if s in scouted_empty and s not in scouted_ships and s not in hits:
                        valid = False; break
                if not valid: continue
                if hits and not any(s in hits for s in sqs):
                    continue
                total_positions += 1
                for s in sqs:
                    probs[s] = probs.get(s, 0) + 1

    # Normalize
    if total_positions > 0:
        for s in probs:
            probs[s] /= total_positions

    return probs, total_positions

def print_heatmap(probs, hits, misses):
    """Print probability heatmap."""
    print("\n  PROBABILITY HEATMAP (%):")
    print("      " + " ".join(f"{c:5d}" for c in range(1, 11)))
    for r in ROWS:
        cells = []
        for c in range(1, 11):
            sq = f"{r}{c}"
            if sq in hits:
                cells.append("  X  ")
            elif sq in misses:
                cells.append("  O  ")
            else:
                pct = probs.get(sq, 0) * 100
                cells.append(f"{pct:4.0f}% ")
        print(f"  {r}  " + " ".join(cells))

    # Top targets
    candidates = [(s, p) for s, p in probs.items() if s not in hits and s not in misses]
    candidates.sort(key=lambda x: -x[1])
    print(f"\n  TOP TARGETS:")
    for sq, p in candidates[:10]:
        print(f"    {sq}: {p*100:.1f}%")

def recommend(hits, misses, scouted_ships, scouted_empty, sunk, credits, costs, turn):
    """Recommend optimal weapon and target."""
    probs, total = compute_probabilities(hits, misses, scouted_ships, scouted_empty, sunk)

    remaining = [s for s in SHIPS if s[0] not in sunk]
    print(f"\n  Remaining ships: {[s[0] for s in remaining]}")
    print(f"  Total valid positions: {total}")
    print(f"  Credits: {credits}")
    print(f"  Costs: {costs}")

    # Check if we have active hits not yet sunk
    active_hits = [h for h in hits]

    print_heatmap(probs, hits, misses)

    # Get top 5 candidates
    candidates = [(s, p) for s, p in probs.items() if s not in hits and s not in misses]
    candidates.sort(key=lambda x: -x[1])

    print(f"\n  RECOMMENDATION:")

    if active_hits:
        print(f"  ⚡ TARGET MODE - Active hits: {active_hits}")

        # Check if bombardment is affordable
        bc = costs.get("bombardment", 5)
        if credits >= bc:
            # Find a hit with unknown neighbors
            for h in active_hits:
                r, c = h[0], int(h[1:])
                ri = ROWS.index(r)
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = ri+dr, c+dc
                    if 0 <= nr < 10 and 1 <= nc <= 10:
                        sq = f"{ROWS[nr]}{nc}"
                        if sq not in misses and sq not in hits:
                            print(f"  > python.exe arsenal_chaos_client.py wait bombard {h}")
                            print(f"  > Reason: Sink ship fast!")
                            return probs

        # Single shot at most likely extension
        singles = [s for s in candidates if s[0] not in active_hits]
        if singles and singles[0][1] > 0:
            print(f"  > python.exe arsenal_chaos_client.py wait {singles[0][0]}")
            print(f"  > Reason: Target mode extension")
            return probs


    # Hunt mode
    salvo_cost = costs.get("salvo", 3)
    if credits >= salvo_cost:
        top3 = candidates[:3]
        if top3 and len(top3) == 3:
            sqs = " ".join([s[0] for s in top3])
            print(f"  > python.exe arsenal_chaos_client.py wait salvo {sqs}")
            print(f"  > Reason: Salvo hunt (p={top3[0][1]*100:.0f}%")
            return probs

    if candidates:
        print(f"  > python.exe arsenal_chaos_client.py wait {candidates[0][0]}")
        print(f"  > Reason: Standard hunt (p={candidates[0][1]*100:.0f}%)")

    return probs

if __name__ == "__main__":
    text = parse_state()
    print(text[:80])
    print("...")
    print("\n=== PARSING ===")
    try:
        hits, misses, scouted_ships, scouted_empty, sunk, credits, turn, costs = extract_data(text)
        print(f"Hits: {hits}")
        print(f"Misses: {sorted(misses)[:20]}... ({len(misses)} total)")
        print(f"Scouted: {scouted_ships}")
        print(f"Empty scouted: {scouted_empty}")
        print(f"Sunk: {sunk}")
        print(f"Credits: {credits}")
        print(f"Turn: {turn}")
        print(f"Costs: {costs}")
        recommend(hits, misses, scouted_ships, scouted_empty, sunk, credits, costs, turn)
    except Exception as e:
        print(f"ERROR: {e}")
        import traceback
        traceback.print_exc()
        print("\nRaw state for debugging:")
        print(text)

